mapper.select:
SELECT P.WRITE_YEAR, P.DOC_TYPE, P.DOC_NO, P.ORGN_ID, P.PLAN_NM || ' (' || D.MINOR_NM || ')' AS planNm, P.RISK_ASSESSMENT_STANDARDS, P.RISK_ALLOWANCE_STANDARDS
  FROM ESG.TB_RISK_ASSESSMENT_PLAN P
  LEFT JOIN ESG.TB_COMMON_D D
    ON D.MAJOR_CD = 'C0027' AND D.MINOR_CD = P.RISK_ASSESSMENT_STANDARDS
 WHERE P.WRITE_YEAR = #{writeYear}
   AND P.ORGN_ID = #{orgnId}
   AND P.COMP_ID = #{compId}
   AND P.USE_YN = 'Y'
   AND P.DOC_NO != #{docNo}
   AND P.RISK_ASSESSMENT_STANDARDS = #{riskAssessmentStandards}
ORDER BY P.DOC_NO::INTEGER ASC

mapper.update:
UPDATE ESG.TB_RISK_ASSESSMENT_PLAN
   SET CPEM_WRITE_YEAR = #{cpemWriteYear},
       CPEM_DOC_NO = #{cpemDocNo},
       UPDATED_AT = NOW(),
       UPDATED_BY = #{updatedBy}
 WHERE WRITE_YEAR = #{writeYear}
   AND DOC_TYPE = #{docType}
   AND DOC_NO = #{docNo}

mapper.delete:
UPDATE ESG.TB_RISK_ASSESSMENT_PLAN
SET USE_YN     = 'N',
    UPDATED_AT = NOW(),
    UPDATED_BY = #{updatedBy}
WHERE WRITE_YEAR = #{writeYear}
  AND DOC_TYPE = #{docType}
  AND DOC_NO = #{docNo}
